// Génère 1-3 événements SAV e-commerce réalistes
const CLIENT_ID = '11366295-d394-486a-8fae-25e25207f83e';

function randomInt(min, max) {
  return Math.floor(Math.random() * (max - min + 1)) + min;
}

function randomOrderId() {
  return '#CMD-' + randomInt(1000, 9999);
}

function generateEvent() {
  const rand = Math.random();
  let event;

  if (rand < 0.15) {
    // ticket_resolved - order_tracking (15%)
    event = {
      client_id: CLIENT_ID,
      event_category: 'ticket_resolved',
      ticket_type: 'order_tracking',
      time_saved_seconds: randomInt(180, 420),
      revenue_amount: 0,
      metadata: { order_id: randomOrderId() },
    };
  } else if (rand < 0.28) {
    // ticket_resolved - address_change (13%)
    event = {
      client_id: CLIENT_ID,
      event_category: 'ticket_resolved',
      ticket_type: 'address_change',
      time_saved_seconds: randomInt(120, 300),
      revenue_amount: 0,
      metadata: { order_id: randomOrderId() },
    };
  } else if (rand < 0.40) {
    // ticket_resolved - return_exchange (12%)
    event = {
      client_id: CLIENT_ID,
      event_category: 'ticket_resolved',
      ticket_type: 'return_exchange',
      time_saved_seconds: randomInt(300, 600),
      revenue_amount: 0,
      metadata: { order_id: randomOrderId() },
    };
  } else if (rand < 0.50) {
    // ticket_resolved - product_info (10%)
    event = {
      client_id: CLIENT_ID,
      event_category: 'ticket_resolved',
      ticket_type: 'product_info',
      time_saved_seconds: randomInt(60, 180),
      revenue_amount: 0,
      metadata: {},
    };
  } else if (rand < 0.60) {
    // ticket_escalated (10%)
    const reasons = [
      'Demande remboursement complexe',
      'Client VIP mécontent',
      'Litige transporteur',
      'Produit défectueux multiple',
    ];
    event = {
      client_id: CLIENT_ID,
      event_category: 'ticket_escalated',
      ticket_type: null,
      time_saved_seconds: 0,
      revenue_amount: 0,
      metadata: { reason: reasons[randomInt(0, reasons.length - 1)] },
    };
  } else if (rand < 0.85) {
    // cart_email_sent (25%)
    const cartValue = randomInt(45, 350);
    event = {
      client_id: CLIENT_ID,
      event_category: 'cart_email_sent',
      ticket_type: null,
      time_saved_seconds: 0,
      revenue_amount: 0,
      metadata: { cart_value: cartValue, email: 'demo@client.com' },
    };
  } else {
    // cart_recovered (15%)
    const amount = randomInt(45, 280);
    event = {
      client_id: CLIENT_ID,
      event_category: 'cart_recovered',
      ticket_type: null,
      time_saved_seconds: 0,
      revenue_amount: amount,
      metadata: { cart_value: amount },
    };
  }

  event.created_at = new Date().toISOString();
  return event;
}

// Générer 1 à 3 événements
const count = randomInt(1, 3);
const events = [];
for (let i = 0; i < count; i++) {
  events.push(generateEvent());
}

return [{ json: { events } }];

// Récupère les événements insérés (retournés par Supabase)
const insertedEvents = $input.all().map(item => item.json);

// Aplatir si c'est un tableau de tableaux
const events = Array.isArray(insertedEvents[0]) ? insertedEvents[0] : insertedEvents;

const CLIENT_ID = '11366295-d394-486a-8fae-25e25207f83e';
const today = new Date().toISOString().split('T')[0]; // YYYY-MM-DD

// Agréger les métriques du batch actuel
let ticketsTotal = 0;
let ticketsAuto = 0;
let totalTimeSaved = 0;
let totalRevenue = 0;
let totalTasks = events.length;

for (const evt of events) {
  if (evt.event_category === 'ticket_resolved') {
    ticketsTotal++;
    ticketsAuto++;
    totalTimeSaved += (evt.time_saved_seconds || 0);
  } else if (evt.event_category === 'ticket_escalated') {
    ticketsTotal++;
  }

  if (evt.event_category === 'cart_recovered') {
    totalRevenue += (evt.revenue_amount || 0);
  }
}

const hoursSaved = totalTimeSaved / 3600;
const timeSavedMinutes = totalTimeSaved / 60;
const estimatedRoi = totalRevenue + (hoursSaved * 25);

return [{
  json: {
    client_id: CLIENT_ID,
    date: today,
    tickets_total: ticketsTotal,
    tickets_auto: ticketsAuto,
    hours_saved: Math.round(hoursSaved * 100) / 100,
    revenue_recovered: totalRevenue,
    tasks_executed: totalTasks,
    time_saved_minutes: Math.round(timeSavedMinutes * 100) / 100,
    estimated_roi: Math.round(estimatedRoi * 100) / 100,
    active_automations: 3
  }
}];

// Récupère les métriques calculées du batch (passées via le node précédent)
// et les métriques existantes du jour (si elles existent)
const currentItems = $input.all();
const existing = currentItems[0]?.json;

// Les métriques du batch sont stockées dans le contexte du workflow
// On les récupère via $('Calculer métriques du jour')
const batchMetrics = $('Calculer métriques du jour').first().json;

const CLIENT_ID = '11366295-d394-486a-8fae-25e25207f83e';
const today = new Date().toISOString().split('T')[0];

// Si des métriques existent déjà pour aujourd'hui, additionner
let merged;
if (existing && existing.client_id) {
  merged = {
    client_id: CLIENT_ID,
    date: today,
    tickets_total: (existing.tickets_total || 0) + batchMetrics.tickets_total,
    tickets_auto: (existing.tickets_auto || 0) + batchMetrics.tickets_auto,
    hours_saved: Math.round(((existing.hours_saved || 0) + batchMetrics.hours_saved) * 100) / 100,
    revenue_recovered: (existing.revenue_recovered || 0) + batchMetrics.revenue_recovered,
    tasks_executed: (existing.tasks_executed || 0) + batchMetrics.tasks_executed,
    time_saved_minutes: Math.round(((existing.time_saved_minutes || 0) + batchMetrics.time_saved_minutes) * 100) / 100,
    estimated_roi: Math.round(((existing.estimated_roi || 0) + batchMetrics.estimated_roi) * 100) / 100,
    active_automations: 3
  };
} else {
  merged = batchMetrics;
}

return [{ json: merged }];
